mapper.update:
UPDATE ATTENDANCE
SET CHECK_OUT  = #{checkOut},
WORK_HOURS = #{workHours},
STATUS     = #{status}
WHERE ATTENDANCE_ID = #{attendanceId}

UPDATE ATTENDANCE
CHECK_IN = #{checkIn}, CHECK_OUT = #{checkOut}, WORK_HOURS = #{workHours}, STATUS = #{status}, MEMO = #{memo},
WHERE ATTENDANCE_ID = #{attendanceId}

mapper.select:
SELECT CASE WHEN COUNT(1) > 0 THEN 1 ELSE 0 END
FROM ATTENDANCE
WHERE EMP_ID = #{empId}
AND WORK_DATE = #{workDate}

SELECT a.*, e.EMP_NAME
FROM ATTENDANCE a
JOIN EMPLOYEE e ON a.EMP_ID = e.EMP_ID
WHERE a.EMP_ID = #{empId}
AND a.WORK_DATE BETWEEN #{from} AND #{to}
ORDER BY a.WORK_DATE DESC

SELECT a.*, e.EMP_NAME
FROM ATTENDANCE a
JOIN EMPLOYEE e ON a.EMP_ID = e.EMP_ID

      AND a.EMP_ID = #{empId} 
     AND e.DEPT_ID = #{deptId} 
     AND a.STATUS = #{status} 
       AND a.WORK_DATE >= #{from} 
         AND a.WORK_DATE <= #{to} 

ORDER BY a.WORK_DATE DESC, e.EMP_NAME
